import React, { useEffect, useRef } from 'react';

const RULES = [
  {
    number: '01',
    title: 'ELIGIBILITY',
    content: (
      <>
        Only <strong>USF Clan Members</strong> can participate. Non-clan members will be disqualified immediately. Register your <strong>IGN</strong> in the{' '}
        <strong>#registration</strong> channel on Discord before the deadline.
      </>
    ),
  },
  {
    number: '02',
    title: 'MATCH FORMAT',
    content: (
      <>
        সকল Match <span className="hl-red">2 vs 2</span> (<span className="hl-yellow">Mode — Gunfight</span>) এ হবে। প্রতি match{' '}
        <span className="hl-red">৬ round</span> এর হবে এবং প্রতি round{' '}
        <span className="hl-yellow">1 minute</span> করে হবে।
      </>
    ),
  },
  {
    number: '03',
    title: 'GUN SELECTION',
    content: (
      <>
        Each match uses a <span className="hl-purple">randomly selected gun</span> from the allowed list. Each player may{' '}
        <span className="hl-red">ban one gun</span> per match before the random pick happens from the remaining guns.
      </>
    ),
  },
  {
    number: '04',
    title: 'CATEGORY SYSTEM',
    content: (
      <>
        Players are divided into <strong>Tier 01 (Elite)</strong> and <strong>Tier 02 (Mid-tier)</strong>. Matches are played within tiers. Prizes are awarded per tier{' '}
        <span className="hl-cyan">separately</span>.
      </>
    ),
  },
  {
    number: '05',
    title: 'FINAL FORMAT',
    content: (
      <>
        Final <span className="hl-yellow">Best of 5</span> series এ খেলা হবে। প্রতিটি match এর জন্য gun এবং map আগে থেকেই নির্ধারণ করা আছে —{' '}
        বিস্তারিত নিচের <span className="hl-cyan">Final Series</span> section এ দেখো।
      </>
    ),
  },
  {
    number: '06',
    title: 'FAIR PLAY',
    content: (
      <>
        <span className="hl-red">No hacks</span>, emulator manipulation, or unsportsmanlike behavior.{' '}
        <span className="hl-yellow">Admin decision is final</span> in all disputes. এছাড়া কোনো player কোথাও{' '}
        <span className="hl-red">৫ সেকেন্ড এর বেশি</span> দাঁড়িয়ে থাকতে পারবে না — তাকে হয়{' '}
        <strong>move</strong> অথবা <strong>fight</strong> করতে হবে।
      </>
    ),
  },
  {
    number: '07',
    title: 'MATCH SCHEDULING',
    content: (
      <>
        All matches must be played <strong>on schedule</strong>. No-shows without prior notice result in a{' '}
        <span className="hl-red">walkover loss</span>.
      </>
    ),
  },
  {
    number: '08',
    title: 'TIER ASSIGNMENT',
    content: (
      <>
        <strong>Management team</strong> সকল player দের Tier নির্বাচন করবে। Player রা তাদের registration confirm হয়েছে কিনা সেটা বুঝতে পারবে{' '}
        <span className="hl-cyan">Players Section</span> এ তাদের নাম আসলে।
      </>
    ),
  },
  {
    number: '09',
    title: 'BRACKET DRAW',
    content: (
      <>
        নিজের <span className="hl-purple">Allies</span> এবং <span className="hl-red">Rivals</span> randomly select করা হবে registered players দের মধ্যে থেকে।
      </>
    ),
  },
];

export default function Rules() {
  const ref = useRef(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const cards = el.querySelectorAll('.rule-card');
    const obs = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('rule-card--visible');
            obs.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.1 }
    );
    cards.forEach((card) => obs.observe(card));
    return () => obs.disconnect();
  }, []);

  return (
    <div className="section animate-up" ref={ref}>
      <style>{`
        .hl-red    { color: #e63946; font-weight: 700; }
        .hl-yellow { color: #f4d03f; font-weight: 700; }
        .hl-cyan   { color: #06b6d4; font-weight: 700; }
        .hl-purple { color: #a78bfa; font-weight: 700; }

        .rules-grid {
          display: grid;
          grid-template-columns: repeat(2, 1fr);
          gap: 20px;
        }

        /* last card spans full width if odd count */
        .rule-card:last-child:nth-child(odd) {
          grid-column: 1 / -1;
          max-width: 50%;
          margin: 0 auto;
          width: 100%;
        }

        .rule-card {
          background: linear-gradient(135deg, var(--card), var(--card2));
          border: 1px solid var(--border);
          border-radius: 16px;
          padding: clamp(20px, 3vw, 32px);
          position: relative;
          overflow: hidden;
          opacity: 0;
          transform: translateY(24px);
          transition: opacity 0.5s ease, transform 0.5s ease, border-color 0.25s, box-shadow 0.25s;
        }
        .rule-card--visible {
          opacity: 1;
          transform: translateY(0);
        }
        .rule-card:hover {
          border-color: rgba(124,58,237,0.45);
          box-shadow: 0 8px 32px rgba(124,58,237,0.12);
        }
        .rule-card::before {
          content: '';
          position: absolute;
          inset: 0;
          background: radial-gradient(ellipse at top left, rgba(124,58,237,0.07), transparent 65%);
          pointer-events: none;
        }

        .rule-number {
          font-family: 'Bebas Neue', sans-serif;
          font-size: clamp(2rem, 5vw, 3rem);
          line-height: 1;
          color: rgba(230,57,70,0.35);
          margin-bottom: 6px;
          letter-spacing: 2px;
        }
        .rule-title {
          font-family: 'Rajdhani', sans-serif;
          font-size: clamp(0.75rem, 1.8vw, 0.9rem);
          font-weight: 700;
          letter-spacing: 3px;
          text-transform: uppercase;
          color: #a78bfa;
          margin-bottom: 12px;
        }
        .rule-body {
          font-size: clamp(0.82rem, 1.6vw, 0.95rem);
          color: var(--text2);
          line-height: 1.75;
        }

        /* stagger animation delay per card */
        .rule-card:nth-child(1)  { transition-delay: 0.05s; }
        .rule-card:nth-child(2)  { transition-delay: 0.10s; }
        .rule-card:nth-child(3)  { transition-delay: 0.15s; }
        .rule-card:nth-child(4)  { transition-delay: 0.20s; }
        .rule-card:nth-child(5)  { transition-delay: 0.25s; }
        .rule-card:nth-child(6)  { transition-delay: 0.30s; }
        .rule-card:nth-child(7)  { transition-delay: 0.35s; }
        .rule-card:nth-child(8)  { transition-delay: 0.40s; }
        .rule-card:nth-child(9)  { transition-delay: 0.45s; }

        @media (max-width: 600px) {
          .rules-grid {
            grid-template-columns: 1fr;
          }
          .rule-card:last-child:nth-child(odd) {
            grid-column: unset;
            max-width: 100%;
          }
        }
      `}</style>

      <div className="section-header">
        <p className="section-tag">Know Before You Play</p>
        <h2 className="section-title">TOURNAMENT RULES</h2>
        <div className="section-line" />
      </div>

      <div className="rules-grid">
        {RULES.map(({ number, title, content }) => (
          <div key={number} className="rule-card">
            <div className="rule-number">{number}</div>
            <div className="rule-title">{title}</div>
            <div className="rule-body">{content}</div>
          </div>
        ))}
      </div>
    </div>
  );
